public void testChiSquareMinimalLength() throws Exception {
        long[] observed = {5, 10};
        double[] expected = {7.5, 7.5};
        assertEquals("chi-square statistic", 2.0833333333333335, testStatistic.chiSquare(expected, observed), 1E-10);
    }

public void testChiSquareWithZeroObserved() throws Exception {
        long[] observed = {0, 10, 10};
        double[] expected = {5, 10, 5};
        assertEquals("chi-square statistic", 10.0, testStatistic.chiSquare(expected, observed), 1E-10);
    }

public void testChiSquareAllEqual() throws Exception {
        long[] observed = {100, 100, 100, 100};
        double[] expected = {100, 100, 100, 100};
        assertEquals("chi-square statistic", 0.0, TestUtils.chiSquare(expected, observed), 1E-12);
    }
